bool astar_next_cell(int gx,int gy,int cx,int cy,uint8_t walls,int* nx,int* ny){
  int dx[]={0,0,1,-1};
  int dy[]={1,-1,0,0};
  int best=-1;int bd=9999;
  for(int d=0;d<4;d++){
    if(walls&(1<<d))continue;
    int tx=cx+dx[d],ty=cy+dy[d];
    if(tx<0||tx>7||ty<0||ty>7)continue;
    int h=abs(tx-gx)+abs(ty-gy);
    if(h<bd){bd=h;best=d;}}
  if(best<0)return false;
  *nx=cx+dx[best];*ny=cy+dy[best];
  return true;
}
